import 'package:cached_network_image/cached_network_image.dart';import 'package:flutter/material.dart';import '../../../Features/ViewBooks/View/view_book.dart';class CustomBooksImage extends StatelessWidget {  final String imageUrl ;  const CustomBooksImage({super.key, required this.imageUrl});  @override  Widget build(BuildContext context) {    return InkWell(        onTap: () => Navigator.push(            context,            MaterialPageRoute(              builder: (context) => const ViewInformationBook(),            )),        child: AspectRatio(            aspectRatio: 2.5 / 4,            child: ClipRRect(              borderRadius: BorderRadius.circular(15.0),              child: CachedNetworkImage(                  filterQuality: FilterQuality.high,                  fit: BoxFit.fill,                  width: 100,                  height: 150,                  placeholder: (context, url) => const Center(                    child: CircularProgressIndicator(),                  ),                  errorWidget: (context, url, error) =>                  const Icon(Icons.warning_amber),                  imageUrl: imageUrl),            ))    );  }}